import React, { useEffect, useState } from 'react';
import { history } from '../api';

export default function Dashboard(){
  const [h, setH] = useState([]);
  const [points, setPoints] = useState(120); // demo points
  useEffect(()=>{ history().then(d=>setH(d||[])); },[]);
  return (
    <div style={{padding:20}}>
      <h2>Gamified Dashboard</h2>
      <div className="card">
        <h3>Points: {points}</h3>
        <p>Complete screenings, mindfulness sessions and daily check-ins to earn more points and streaks.</p>
        <button onClick={()=>setPoints(p=>p+10)}>+10 (demo)</button>
      </div>
      <div style={{marginTop:20}}>
        <h3>Recent Screenings</h3>
        <ul>
          {h.map(r=>(<li key={r.id}>{r.type} — {r.score} ({r.category}) at {new Date(r.created_at).toLocaleString()}</li>))}
        </ul>
      </div>
    </div>
  );
}
